using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN=5e5+5;
int n,m,a[MAXN],ans=0,sum;
map<int,int> mp;
int main(void)
{
//
	//freopen("xx.out","w",stdout);
	cin>>n>>m;
	mp[0]=1;
	for(int i=1;i<=n;++i)
	{
		cin>>a[i];
		sum^=a[i];
		if(mp.find(sum^m)==mp.end())
		{
			mp[sum]=1;
		}
		else
		{
			++ans;
			sum=0;
			mp.clear();
			mp[0]=1;
		}
	}
	cout<<ans;
	return false;
}
